def parse_table(self, text: str) -> List[Dict[str, str]]:
    """Parse a markdown table into a list of dicts."""
    lines = [l.strip() for l in text.strip().split('\n') if l.strip()]
    if len(lines) < 3:
        return []
    # Parse header row
    headers = [h.strip() for h in lines[0].strip('|').split('|')]
    # Skip separator row (line 1), parse data rows
    rows = []
    for line in lines[2:]:
        if not line.startswith('|'):
            break
        values = [v.strip() for v in line.strip('|').split('|')]
        row = {h: v for h, v in zip(headers, values)}
        rows.append(row)
    return rows
